def count_subsets(nums, target):
    n = len(nums)
    count = 0
    def go(i, remain):
        nonlocal count
        if i == n:
            if remain == 0:
                count += 1
            return
        go(i + 1, remain - nums[i])
        go(i + 1, remain)
    go(0, target)
    return count
